{/* ── HEADER con nav secundaria + usuario ── */}
<header
  className="px-6 flex items-center gap-4 flex-shrink-0"
  style={{
    background: "#FDFDFB",
    borderBottom: "1px solid #DDDFE2",
    minHeight: "56px",
  }}
>
  {/* Título de la página */}
  <div className="min-w-0 mr-2 flex-1">
    <h1 className="text-base font-bold leading-tight truncate" style={{ color: "#031E43" }}>
      {meta.title}
    </h1>
    <p className="text-[11px] leading-tight truncate" style={{ color: "#3B506D" }}>
      {meta.subtitle}
    </p>
  </div>

  {/* Search bar */}
  <div className="relative hidden md:block">
    <i className="ti ti-search absolute left-3 top-1/2 -translate-y-1/2 text-sm" style={{ color: "#A3A7AD" }} />
    <input
      type="text"
      placeholder="Buscar..."
      className="pl-8 pr-4 py-1.5 rounded-full text-xs border focus:outline-none focus:ring-2 w-48 transition-shadow"
      style={{ borderColor: "#DDDFE2", backgroundColor: "#FFFFFF", color: "#031E43" }}
      onFocus={e => (e.currentTarget.style.boxShadow = "0 0 0 2px rgba(196,154,44,.25)")}
      onBlur={e => (e.currentTarget.style.boxShadow = "")}
    />
  </div>

  {/* Notificaciones */}
  <div className="relative flex-shrink-0" ref={notifRef}>
    <button
      onClick={() => setNotifOpen(v => !v)}
      className="relative w-8 h-8 flex items-center justify-center rounded-lg transition-all"
      style={{ color: "#3B506D" }}
      onMouseOver={e => (e.currentTarget.style.background = "#DDDFE2")}
      onMouseOut={e => (e.currentTarget.style.background = "transparent")}
      title="Notificaciones"
    >
      <i className="ti ti-bell text-base" />
      <span className="absolute top-1.5 right-1.5 w-2 h-2 rounded-full border-2 border-white" style={{ backgroundColor: "#C49A2C" }} />
    </button>
    {notifOpen && (
      <div className="absolute right-0 top-full mt-2 w-72 rounded-xl shadow-lg border z-50 overflow-hidden"
        style={{ background: "#FFFFFF", borderColor: "#DDDFE2" }}>
        <div className="px-4 py-3 border-b" style={{ borderColor: "#DDDFE2" }}>
          <p className="text-xs font-bold" style={{ color: "#031E43" }}>Notificaciones</p>
        </div>
        {[
          { icon: "ti-robot", color: "#C49A2C", bg: "#FEF3C7", msg: "Agente IA respondió 142 mensajes hoy", time: "Hace 5 min" },
          { icon: "ti-alert-triangle", color: "#F59E0B", bg: "#FEF3C7", msg: "TKT-0234 por vencer en 30 min", time: "Hace 8 min" },
          { icon: "ti-trending-up", color: "#3B82F6", bg: "#EFF6FF", msg: "Deal cerrado: Grupo Textil SA — $55K", time: "Hace 22 min" },
        ].map((n, i) => (
          <div key={i} className="flex items-start gap-3 px-4 py-3 hover:bg-gray-50 transition-colors cursor-pointer border-b last:border-0" style={{ borderColor: "#F3F4F6" }}>
            <div className="w-7 h-7 rounded-lg flex items-center justify-center flex-shrink-0" style={{ backgroundColor: n.bg }}>
              <i className={`ti ${n.icon} text-sm`} style={{ color: n.color }} />
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-[11px] font-medium leading-tight" style={{ color: "#031E43" }}>{n.msg}</p>
              <p className="text-[10px] mt-0.5" style={{ color: "#A3A7AD" }}>{n.time}</p>
            </div>
          </div>
        ))}
        <div className="px-4 py-2.5 text-center">
          <button className="text-[11px] font-semibold" style={{ color: "#C49A2C" }}>Ver todas las notificaciones</button>
        </div>
      </div>
    )}
  </div>

  {/* Nav secundaria + usuario */}
  <div className="flex items-center gap-1 flex-shrink-0">

